    `capacity_gallons` DECIMAL(18,2) COMMENT 'Maximum storage capacity of the bulk tank measured in gallons, representing the total volume the tank can hold.',
    `capacity_liters` DECIMAL(18,2) COMMENT 'Maximum storage capacity of the bulk tank measured in liters, used for international reporting and metric system operations.',
    `certification_expiration_date` DATE COMMENT 'Date when the current regulatory certification for the bulk tank expires and renewal is required.',
    `certification_number` STRING COMMENT 'Official certification or registration number issued by regulatory authorities for the bulk tank, required for dairy and food storage compliance.',
    `cleaning_frequency_days` STRING COMMENT 'Required interval in days between cleaning cycles for the bulk tank to maintain sanitation standards and regulatory compliance.',
    `cooling_system_type` STRING COMMENT 'Type of refrigeration or cooling system integrated with the bulk tank for temperature-sensitive storage such as milk.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this bulk tank record was first created in the system.',
    `inlet_valve_count` STRING COMMENT 'Number of inlet valves or ports on the bulk tank for receiving product from milking systems or other sources.',
    `installation_date` DATE COMMENT 'Date when the bulk tank was installed and commissioned for use at the facility.',
    `insulation_type` STRING COMMENT 'Type of thermal insulation applied to the bulk tank to maintain temperature control for stored contents.',
    `last_cleaning_date` DATE COMMENT 'Date when the bulk tank was last cleaned and sanitized according to standard operating procedures.',
    `last_inspection_date` DATE COMMENT 'Date of the most recent safety or regulatory inspection performed on the bulk tank.',
    `manufacturer` STRING COMMENT 'Name of the company that manufactured the bulk tank equipment.',
    `material_construction` STRING COMMENT 'Primary material used in the construction of the bulk tank, affecting durability, cleaning requirements, and suitability for different storage contents.',
    `model_number` STRING COMMENT 'Manufacturer-assigned model number or designation for the bulk tank, used for parts ordering and maintenance specifications.',
    `modified_timestamp` TIMESTAMP COMMENT 'Timestamp when this bulk tank record was last updated or modified in the system.',
    `next_inspection_due_date` DATE COMMENT 'Scheduled date for the next required inspection of the bulk tank to maintain compliance and operational safety.',
    `notes` STRING COMMENT 'Free-form text field for recording additional information, special handling requirements, or operational notes about the bulk tank.',
    `outlet_valve_count` STRING COMMENT 'Number of outlet valves or discharge ports on the bulk tank for transferring product to tanker trucks or processing lines.',
    `purchase_date` DATE COMMENT 'Date when the bulk tank was purchased by the farm operation, used for asset depreciation and lifecycle tracking.',
    `purchase_price` DECIMAL(18,2) COMMENT 'Original purchase price paid for the bulk tank equipment, used for capital asset valuation and depreciation calculations.',
    `serial_number` STRING COMMENT 'Unique serial number assigned by the manufacturer to this specific bulk tank unit for warranty and service tracking.',
    `bulk_tank_status` STRING COMMENT 'Current operational status of the bulk tank indicating availability for use in livestock operations.',
    `tank_name` STRING COMMENT 'Human-readable name or label assigned to the bulk tank for easy identification by farm personnel.',
    `tank_number` STRING COMMENT 'Business identifier for the bulk tank, typically displayed on signage and used in operational communications.',
    `tank_type` STRING COMMENT 'Classification of the bulk tank based on its primary storage purpose within livestock operations.',
    `target_temperature_fahrenheit` DECIMAL(18,2) COMMENT 'Desired operating temperature for the bulk tank contents measured in degrees Fahrenheit, critical for milk and other perishable storage.',
    `temperature_monitoring_enabled` BOOLEAN COMMENT 'Indicates whether the bulk tank has automated temperature monitoring and recording capabilities for quality control and compliance.',
    `warranty_expiration_date` DATE COMMENT 'Date when the manufacturer warranty coverage for the bulk tank expires.',
    CONSTRAINT pk_bulk_tank PRIMARY KEY(`bulk_tank_id`)
) COMMENT 'Master reference table for bulk_tank. Referenced by bulk_tank_id.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`livestock`.`semen_canister` (
    `semen_canister_id` BIGINT COMMENT 'Primary key for semen_canister',
    `facility_id` BIGINT COMMENT 'Identifier of the facility or location where the canister is currently stored or assigned.',
