    `alarm_system_type` STRING COMMENT 'Type of alarm system installed on the canister for temperature or level alerts.',
    `assigned_species` STRING COMMENT 'Primary animal species for which this canister is designated to store semen (e.g., bovine, porcine, equine, ovine, caprine).',
    `barcode` STRING COMMENT 'Barcode identifier printed or attached to the canister for scanning and inventory control.',
    `canister_number` STRING COMMENT 'Externally-known unique identification number or code assigned to the semen canister for tracking and inventory management.',
    `canister_type` STRING COMMENT 'Classification of the canister based on its design and intended use (e.g., liquid nitrogen storage, dry shipper, vapor shipper, portable, stationary, transport).',
    `certification_expiration_date` DATE COMMENT 'Date when the canisters certification or compliance approval expires and recertification is required.',
    `certification_number` STRING COMMENT 'Certification or compliance number issued by regulatory or industry bodies for the canister.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this canister record was first created in the system.',
    `currency_code` STRING COMMENT 'Three-letter ISO 4217 currency code for the purchase cost.',
