    `decommission_reason` STRING COMMENT 'Reason for decommissioning the canister (e.g., end of useful life, damage, obsolescence, regulatory non-compliance).',
    `diameter_cm` DECIMAL(18,2) COMMENT 'Outer diameter of the canister in centimeters.',
    `height_cm` DECIMAL(18,2) COMMENT 'Overall height of the canister in centimeters.',
    `is_mobile` BOOLEAN COMMENT 'Indicates whether the canister is designed for mobile or transport use versus stationary storage.',
    `last_maintenance_date` DATE COMMENT 'Date when the canister last underwent maintenance, inspection, or servicing.',
    `last_nitrogen_refill_date` DATE COMMENT 'Date when the canister was last refilled with liquid nitrogen.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this canister record was last modified or updated.',
    `liquid_nitrogen_capacity_liters` DECIMAL(18,2) COMMENT 'Maximum liquid nitrogen capacity of the canister measured in liters.',
    `manufacturer_name` STRING COMMENT 'Name of the company that manufactured the semen canister.',
    `model_number` STRING COMMENT 'Manufacturers model number or designation for the canister design.',
    `neck_opening_diameter_mm` DECIMAL(18,2) COMMENT 'Diameter of the canister neck opening in millimeters, which determines compatible storage racks and canes.',
    `next_maintenance_due_date` DATE COMMENT 'Scheduled date for the next required maintenance or inspection of the canister.',
    `notes` STRING COMMENT 'Free-text field for additional notes, comments, or special instructions related to the canister.',
    `purchase_cost` DECIMAL(18,2) COMMENT 'Original purchase cost of the canister in the organizations base currency.',
    `purchase_date` DATE COMMENT 'Date when the canister was purchased or acquired by the organization.',
    `rfid_tag_number` STRING COMMENT 'RFID tag number attached to the canister for automated tracking and inventory management.',
    `serial_number` STRING COMMENT 'Unique serial number assigned by the manufacturer to this specific canister unit.',
    `static_holding_time_days` STRING COMMENT 'Number of days the canister can maintain cryogenic temperatures under static conditions without refilling liquid nitrogen.',
    `semen_canister_status` STRING COMMENT 'Current lifecycle status of the semen canister indicating its operational state and availability for use.',
    `storage_capacity_units` STRING COMMENT 'Maximum number of semen storage units (straws, vials, or ampules) that the canister can hold.',
    `storage_location_code` STRING COMMENT 'Specific storage location code or designation within the facility (e.g., room number, bay, rack position).',
    `temperature_monitoring_enabled` BOOLEAN COMMENT 'Indicates whether the canister is equipped with automated temperature monitoring and alarm systems.',
    `warranty_expiration_date` DATE COMMENT 'Date when the manufacturers warranty for the canister expires.',
    `weight_empty_kg` DECIMAL(18,2) COMMENT 'Weight of the empty canister in kilograms without liquid nitrogen or stored samples.',
    CONSTRAINT pk_semen_canister PRIMARY KEY(`semen_canister_id`)
) COMMENT 'Master reference table for semen_canister. Referenced by canister_id.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`livestock`.`herd_vaccination_schedule` (
    `herd_vaccination_schedule_id` BIGINT COMMENT 'Primary key for herd_vaccination_schedule',
    `parent_herd_vaccination_schedule_id` BIGINT COMMENT 'Self-referencing FK on herd_vaccination_schedule (parent_herd_vaccination_schedule_id)',
    `administration_route` STRING COMMENT 'Method by which the vaccine is administered to the animal.',
    `animal_category` STRING COMMENT 'Age or production category of animals this schedule targets (e.g., calf, heifer, sow, broiler).',
    `animal_species` STRING COMMENT 'Species of livestock this vaccination schedule applies to.',
    `booster_interval_months` STRING COMMENT 'Number of months between booster vaccinations for ongoing immunity maintenance. Null if no booster is required.',
    `booster_required_flag` BOOLEAN COMMENT 'Indicates whether a booster vaccination is required after the initial dose series to maintain immunity.',
    `certification_required_flag` BOOLEAN COMMENT 'Indicates whether official veterinary certification or documentation is required after vaccination for regulatory compliance or interstate movement.',
    `cost_per_dose` DECIMAL(18,2) COMMENT 'Standard cost per dose of vaccine for budgeting and cost analysis purposes. Business-confidential pricing information.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this vaccination schedule record was first created in the system.',
    `disease_target` STRING COMMENT 'Primary disease or pathogen this vaccination schedule is designed to prevent (e.g., Foot and Mouth Disease, Brucellosis, Avian Influenza).',
    `dosage_amount` DECIMAL(18,2) COMMENT 'Quantity of vaccine to be administered per animal in a single dose.',
    `dosage_unit` STRING COMMENT 'Unit of measure for the vaccine dosage (milliliters, cubic centimeters, milligrams, or standard dose).',
    `effective_end_date` DATE COMMENT 'Date on which this vaccination schedule is retired or no longer valid. Null for schedules with no planned end date.',
    `effective_start_date` DATE COMMENT 'Date on which this vaccination schedule becomes active and available for use in herd management operations.',
    `herd_immunity_threshold_percent` DECIMAL(18,2) COMMENT 'Minimum percentage of the herd that must be vaccinated to achieve herd immunity and prevent disease outbreak.',
    `interval_between_doses_days` STRING COMMENT 'Number of days required between doses for multi-dose vaccination protocols. Null for single-dose schedules.',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Timestamp when this vaccination schedule record was last updated or modified.',
    `maximum_age_days` STRING COMMENT 'Maximum age of the animal in days by which the vaccination should be completed. Null if no upper age limit applies.',
    `minimum_age_days` STRING COMMENT 'Minimum age of the animal in days at which the first dose of this vaccine should be administered.',
    `notes` STRING COMMENT 'Additional notes, special instructions, or considerations for administering this vaccination schedule (e.g., contraindications, special handling requirements).',
    `number_of_doses` STRING COMMENT 'Total number of doses required to complete the vaccination protocol (e.g., 1 for single-dose, 2 for primary and booster).',
    `regulatory_authority` STRING COMMENT 'Name of the government agency or regulatory body mandating this vaccination (e.g., USDA APHIS, State Veterinarian Office). Null if not regulatory-mandated.',
    `regulatory_requirement_flag` BOOLEAN COMMENT 'Indicates whether this vaccination is mandated by federal, state, or local regulatory authorities (e.g., APHIS-required brucellosis vaccination).',
    `schedule_code` STRING COMMENT 'Externally-known unique business identifier for the vaccination schedule, used for operational reference and regulatory reporting.',
    `schedule_name` STRING COMMENT 'Human-readable name of the vaccination schedule program (e.g., Spring Cattle Vaccination Protocol, Swine Respiratory Disease Prevention).',
    `schedule_status` STRING COMMENT 'Current lifecycle status of the vaccination schedule indicating whether it is actively in use, temporarily suspended, or retired.',
    `seasonal_timing` STRING COMMENT 'Recommended season or time of year for administering this vaccination to align with disease risk periods or production cycles.',
    `shelf_life_months` STRING COMMENT 'Duration in months that the vaccine remains effective when stored under proper conditions.',
    `storage_temperature_max_celsius` DECIMAL(18,2) COMMENT 'Maximum storage temperature in Celsius required to maintain vaccine efficacy and stability.',
    `storage_temperature_min_celsius` DECIMAL(18,2) COMMENT 'Minimum storage temperature in Celsius required to maintain vaccine efficacy and stability.',
    `vaccine_manufacturer` STRING COMMENT 'Name of the pharmaceutical company or manufacturer producing the vaccine.',
    `vaccine_product_code` STRING COMMENT 'Manufacturers product code or catalog number for the vaccine.',
    `vaccine_type` STRING COMMENT 'Type or name of the vaccine administered under this schedule (e.g., Bovine Respiratory Disease Complex, Clostridial 7-Way).',
    `version_number` STRING COMMENT 'Version number of the vaccination schedule to track revisions and updates to protocols over time.',
    `veterinarian_approval_required_flag` BOOLEAN COMMENT 'Indicates whether a licensed veterinarian must approve or supervise the administration of this vaccination.',
    `withdrawal_period_days` STRING COMMENT 'Number of days required between vaccination and slaughter or milk/egg collection to ensure no residues remain in animal products. Critical for FSIS compliance.',
    CONSTRAINT pk_herd_vaccination_schedule PRIMARY KEY(`herd_vaccination_schedule_id`)
) COMMENT 'Master reference table for herd_vaccination_schedule. Referenced by herd_vaccination_schedule_id.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`livestock`.`barn` (
