    `country_code` STRING COMMENT 'Three-letter ISO country code where the barn is located.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the barn record was first created in the system.',
    `current_occupancy_count` STRING COMMENT 'Current number of animals housed in the barn at the time of record.',
    `emergency_contact_name` STRING COMMENT 'Name of the primary emergency contact person responsible for the barn facility during incidents or emergencies.',
    `emergency_contact_phone` STRING COMMENT 'Primary phone number for the emergency contact person responsible for the barn facility.',
