    `floor_area_sqft` DECIMAL(18,2) COMMENT 'Total usable floor area of the barn measured in square feet, used for space planning and animal welfare compliance.',
    `flooring_type` STRING COMMENT 'Type of flooring material used in the barn, affecting animal comfort, hygiene, and maintenance requirements.',
    `last_inspection_date` DATE COMMENT 'Date of the most recent regulatory or internal inspection of the barn facility for compliance and safety verification.',
    `last_renovation_date` DATE COMMENT 'Date of the most recent major renovation or structural upgrade to the barn facility.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'Timestamp when the barn record was most recently modified in the system.',
    `latitude` DECIMAL(18,2) COMMENT 'Geographic latitude coordinate of the barn facility for mapping and location-based analytics.',
    `longitude` DECIMAL(18,2) COMMENT 'Geographic longitude coordinate of the barn facility for mapping and location-based analytics.',
    `next_scheduled_inspection_date` DATE COMMENT 'Planned date for the next regulatory or internal inspection of the barn facility.',
    `notes` STRING COMMENT 'Free-text field for additional operational notes, special instructions, or contextual information about the barn facility.',
    `pen_count` STRING COMMENT 'Total number of individual pens or enclosures within the barn for animal grouping and management.',
    `postal_code` STRING COMMENT 'Postal or ZIP code for the barn facility location.',
    `state_province` STRING COMMENT 'Two-letter state or province code where the barn is located.',
    `barn_status` STRING COMMENT 'Current operational status of the barn facility indicating its availability and lifecycle state.',
    `ventilation_system_type` STRING COMMENT 'Type of ventilation system installed in the barn to maintain air quality and temperature control for animal health.',
    `waste_management_system` STRING COMMENT 'Type of manure and waste management system employed at the barn for environmental compliance and operational efficiency.',
    `water_source_type` STRING COMMENT 'Primary source of water supply for the barn used for animal drinking and facility operations.',
    CONSTRAINT pk_barn PRIMARY KEY(`barn_id`)
